{"code": "import subprocess, json

# 1. CI/CD audit - repos without ci.yml or deploy.yml
r = subprocess.run(["gh", "api", "orgs/Ai-Whisperers/repos?per_page=100"],
                   capture_output=True, text=True, timeout=20)
repos = [r["name"] for r in json.loads(r.stdout) if not r["archived"]]
print(f"Total active repos: {len(repos)}")

def check_file(repo, path):
    r = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/contents/{path}"],
                       capture_output=True, text=True, timeout=10)
    return r.returncode == 0

no_ci = []
no_deploy = []
for repo in repos:
    has_ci = check_file(repo, ".github/workflows/ci.yml")
    has_deploy = check_file(repo, ".github/workflows/deploy.yml")
    if not has_ci:
        no_ci.append(repo)
    if not has_deploy:
        no_deploy.append(repo)

print(f"\n=== Missing CI ({len(no_ci)}) ===")
for r in no_ci: print(f"  {r}")
print(f"\n=== Missing Deploy ({len(no_deploy)}) ===")
for r in no_deploy: print(f"  {r}")

# 2. What packages are possible to extract?
# Categories of things in elviajero not yet packaged:
print("\n\n=== EXTRACTION CANDIDATES FROM EL VIAJERO ===")

# API route patterns
r2 = subprocess.run(["ssh", "-o", "StrictHostKeyChecking=accept-new", "root@72.61.44.159",
                     "find", "/root/elviajero-comercio/app/api", "-name", "route.ts"],
                    capture_output=True, text=True, timeout=15)
api_routes = [f.split("/root/elviajero-comercio/app/api/")[1].replace("/route.ts", "") for f in r2.stdout.strip().split("\n") if f]
print(f"\nAPI routes: {len(api_routes)}")
for r in sorted(api_routes):
    print(f"  api/{r}")

# Components not extracted
r3 = subprocess.run(["ssh", "-o", "StrictHostKeyChecking=accept-new", "root@72.61.44.159",
                     "find", "/root/elviajero-comercio/components", "-name", "*.tsx", "-not", "-path", "*/node_modules/*"],
                    capture_output=True, text=True, timeout=15)
all_components = [f.split("/root/elviajero-comercio/components/")[1] for f in r3.stdout.strip().split("\n") if f]
print(f"\nAll components: {len(all_components)}")

# Categorize
ui_bits = {"button", "card", "data-table", "dialog", "chart-card"}
extracted_already = {"analytics", "cookie-consent", "whatsapp-float", "admin-layout", "sidebar", "image-upload", "charts", "ui"}
extracted_admin = {"badge-config", "product-search", "charts", "notifications", "duplicate-warning", "activity-log", "ui", "sidebar", "image-upload", "order-date-filter"}
extracted_ui = {"ui", "chart-card", "button", "card", "data-table", "dialog"}

print("\n--- NOT extracted yet ---")
for c in sorted(set(c.replace("admin/", "") for c in all_components)):
    if c.startswith("admin/"):
        name = c.replace("admin/", "")
        if name not in extracted_admin:
            print(f"  [admin] {name}")
    elif c.startswith("ui/"):
        name = c.replace("ui/", "")
        if name not in extracted_ui:
            print(f"  [ui] {name}")
    elif c.startswith("pages/"):
        print(f"  [page] {c}")
    elif c.startswith("header/"):
        print(f"  [header] {c}")
    elif c.startswith("animations/"):
        print(f"  [anim] {c}")
    else:
        name = c.replace(".tsx", "")
        if name not in extracted_already:
            print(f"  [comp] {name}")
"}

{"code": "import subprocess, json

# Final check: what repos don't use our ci-cd workflows
r = subprocess.run(["gh", "api", "orgs/Ai-Whisperers/repos?per_page=100"],
                   capture_output=True, text=True, timeout=15)
repos = [r["name"] for r in json.loads(r.stdout) if not r["archived"]]

# Check which have any workflow referencing ci-cd repo
no_cicd = []
for repo in repos:
    if repo in [".github", "AI-Whisperers", "legal", "work-coordination", "ci-cd"]:
        continue
    r2 = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/contents/.github/workflows"],
                        capture_output=True, text=True, timeout=8)
    if r2.returncode == 0:
        wfs = json.loads(r2.stdout)
        if not wfs:
            no_cicd.append(f"{repo:30s} NO workflows")
            continue
        uses_cicd = False
        fnames = [w["name"] for w in wfs if w["type"] == "file"]
        for fn in fnames:
            r3 = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/contents/.github/workflows/{fn}"],
                               capture_output=True, text=True, timeout=8)
            if r3.returncode == 0:
                import base64
                content = base64.b64decode(json.loads(r3.stdout)["content"]).decode()
                if "Ai-Whisperers/ci-cd" in content:
                    uses_cicd = True
                    break
        if not uses_cicd:
            no_cicd.append(f"{repo:30s} NO ci-cd refs ({','.join(fnames[:3])})")
    else:
        no_cicd.append(f"{repo:30s} NO workflows dir")

print(f"Repos without ci-cd integration ({len(no_cicd)}):")
for r in sorted(no_cicd):
    print(f"  {r}")
"}
